@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="wrapperElement">@ChildContent</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference wrapperElement;
    private IJSObjectReference? module;
    private DotNetObjectReference<UserActivityTracker>? dotNetRef;
    private CancellationTokenSource? delayCts;
    private bool isIdle;
    private int timeoutSeconds;

    protected override void OnParametersSet()
    {
        timeoutSeconds = TimeoutSeconds;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/UserActivityTracker.razor.js");
            await module.InvokeVoidAsync("initialize", wrapperElement, dotNetRef);
            ResetTimer();
        }
    }

    [JSInvokable]
    public void OnActivity()
    {
        ResetTimer();

        if (isIdle)
        {
            isIdle = false;
            _ = NotifyActiveCore();
        }
    }

    private async Task NotifyActiveCore()
    {
        try
        {
            await OnActive.InvokeAsync();
        }
        catch (Exception ex)
        {
            await DispatchExceptionAsync(ex);
        }
    }

    private void ResetTimer()
    {
        delayCts?.Cancel();
        delayCts?.Dispose();
        delayCts = new CancellationTokenSource();
        _ = RunTimerCore(delayCts.Token);
    }

    private async Task RunTimerCore(CancellationToken token)
    {
        try
        {
            await Task.Delay(timeoutSeconds * 1000, token);
            isIdle = true;
            await OnIdle.InvokeAsync();
        }
        catch (OperationCanceledException)
        {
            // Timer was reset — expected.
        }
        catch (Exception ex)
        {
            await DispatchExceptionAsync(ex);
        }
    }

    public async ValueTask DisposeAsync()
    {
        delayCts?.Cancel();
        delayCts?.Dispose();

        if (module is not null)
        {
            try { await module.InvokeVoidAsync("dispose"); }
            catch (JSDisconnectedException) { }
            try { await module.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }

        dotNetRef?.Dispose();
    }
}

let element = null;
let dotNetRef = null;

function handleActivity() {
    dotNetRef?.invokeMethodAsync("OnActivity");
}

const events = ["mousemove", "keydown", "click", "scroll"];

export function initialize(el, ref) {
    element = el;
    dotNetRef = ref;
    for (const evt of events) {
        element.addEventListener(evt, handleActivity, { passive: true });
    }
}

export function dispose() {
    if (element) {
        for (const evt of events) {
            element.removeEventListener(evt, handleActivity);
        }
    }
    element = null;
    dotNetRef = null;
}

